100:   it('uses custom label as aria-label', () => {
101:     render(<Sparkline data={[0.5, 0.7]} label="relevance trend" />);
102:     expect(screen.getByLabelText('relevance trend')).toBeInTheDocument();
103:   });
104: 
105:   it('uses default aria-label when none provided', () => {
106:     render(<Sparkline data={[0.5, 0.7]} />);
107:     expect(screen.getByLabelText('Score trend sparkline')).toBeInTheDocument();
108:   });
109: 
110:   it('respects custom width and height', () => {
111:     const { container } = render(<Sparkline data={[0.5, 0.7]} width={120} height={40} />);
112:     const svg = container.querySelector('svg');
113:     expect(svg).toHaveAttribute('width', '120');
114:     expect(svg).toHaveAttribute('height', '40');
115:   });
116: 
117:   it('uses custom color on polyline stroke', () => {
118:     const { container } = render(<Sparkline data={[0.5, 0.7]} color="#ff0000" />);
119:     const polyline = container.querySelector('polyline');
120:     expect(polyline).toHaveAttribute('stroke', '#ff0000');
121:   });
122: 
123:   it('renders null when only 1 of multiple is finite', () => {
124:     const { container } = render(<Sparkline data={[NaN, Infinity, 0.5]} />);
125:     // Only 1 valid (0.5), renders null
126:     expect(container.firstChild).toBeNull();
127:   });
128: });
