134: // Pinned epoch for all time-relative assertions in this describe block
135: const PINNED_NOW = new Date('2026-02-22T12:00:00.000Z');
136: 
137: describe('TrendChart', () => {
138:   beforeEach(() => {
139:     vi.useFakeTimers();
140:     vi.setSystemTime(PINNED_NOW);
141:   });
142:   afterEach(() => {
143:     vi.useRealTimers();
144:   });
145: 
146:   it('renders empty state when no trend provided', () => {
147:     render(<TrendChart metricName="relevance" />);
148:     expect(screen.getByText('No trend data available')).toBeInTheDocument();
149:   });
150: 
151:   it('renders chart container with aria-label when trend provided', () => {
152:     render(<TrendChart trend={makeTrend()} metricName="relevance" />);
153:     expect(screen.getByLabelText('Trend chart for relevance')).toBeInTheDocument();
154:   });
155: 
156:   it('shows projection data when dynamics.velocity is non-zero', () => {
157:     const trend = makeTrend();
158:     const dynamics = makeDynamics({ velocity: 0.05 });
159:     render(<TrendChart trend={trend} dynamics={dynamics} metricName="relevance" />);
160:     // velocity is shown in the dynamics section
161:     expect(screen.getByText('Velocity:')).toBeInTheDocument();
162:     expect(screen.getByText('Acceleration:')).toBeInTheDocument();
163:   });
164: 
165:   it('does not show dynamics section when dynamics is undefined', () => {
166:     render(<TrendChart trend={makeTrend()} metricName="relevance" />);
167:     expect(screen.queryByText('Velocity:')).toBeNull();
168:   });
169: 
170:   it('shows zero-velocity dynamics section without projection', () => {
171:     const dynamics = makeDynamics({ velocity: 0 });
172:     render(<TrendChart trend={makeTrend()} dynamics={dynamics} metricName="relevance" />);
173:     expect(screen.getByText('Velocity:')).toBeInTheDocument();
174:     // No "Breach in" when velocity is 0 and no projectedBreachTime
175:     expect(screen.queryByText('Breach in:')).toBeNull();
176:   });
177: 
178:   it('shows breach time when projectedBreachTime is provided', () => {
179:     // Project breach 25h from pinned now — renders as "25.0h"
180:     const futureIso = new Date(PINNED_NOW.getTime() + 25 * 60 * 60 * 1000).toISOString();
181:     const dynamics = makeDynamics({
182:       velocity: 0.05,
183:       projectedBreachTime: futureIso,
184:       projectedStatus: 'warning',
185:     });
186:     render(<TrendChart trend={makeTrend()} dynamics={dynamics} metricName="relevance" />);
187:     expect(screen.getByText('Breach in:')).toBeInTheDocument();
188:     expect(screen.getByText('25.0h')).toBeInTheDocument();
189:   });
190: 
191:   it('shows "threshold exceeded" for breach in the past', () => {
192:     const pastIso = new Date(PINNED_NOW.getTime() - 1 * 60 * 60 * 1000).toISOString();
193:     const dynamics = makeDynamics({
194:       velocity: 0.05,
195:       projectedBreachTime: pastIso,
196:       projectedStatus: 'critical',
197:     });
198:     render(<TrendChart trend={makeTrend()} dynamics={dynamics} metricName="relevance" />);
199:     expect(screen.getByText('threshold exceeded')).toBeInTheDocument();
200:   });
201: 
202:   it('shows breach in minutes for sub-1h breach', () => {
203:     // 30 minutes from pinned now → "30m"
204:     const futureIso = new Date(PINNED_NOW.getTime() + 30 * 60 * 1000).toISOString();
205:     const dynamics = makeDynamics({
206:       velocity: 0.05,
207:       projectedBreachTime: futureIso,
208:       projectedStatus: 'warning',
209:     });
210:     render(<TrendChart trend={makeTrend()} dynamics={dynamics} metricName="relevance" />);
211:     expect(screen.getByText('30m')).toBeInTheDocument();
212:   });
213: 
214:   it('shows breach in days for 2d+ breach', () => {
215:     // 3 days from pinned now → "3.0d"
216:     const futureIso = new Date(PINNED_NOW.getTime() + 3 * 24 * 60 * 60 * 1000).toISOString();
217:     const dynamics = makeDynamics({
218:       velocity: 0.05,
219:       projectedBreachTime: futureIso,
