351: });  1: /**
  2:  * Tests for useQualityLive hook.
  3:  *
  4:  * Uses vi.useFakeTimers() + vi.advanceTimersByTimeAsync() to control
  5:  * setInterval polling without triggering infinite timer loops.
  6:  *
  7:  * Pattern:
  8:  *   - Flush initial async fetch: advanceTimersByTimeAsync(0) (flushes microtasks)
  9:  *   - Trigger one poll interval: advanceTimersByTimeAsync(30_000)
 10:  *   - Never use vi.runAllTimersAsync() — it loops infinitely on setInterval
 11:  */
 12: 
 13: import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
 14: import { renderHook, act } from '@testing-library/react';
 15: import { useQualityLive } from '../hooks/useQualityLive.js';
 16: 
 17: // ---------------------------------------------------------------------------
 18: // Mock fetch globally
 19: // ---------------------------------------------------------------------------
 20: 
 21: const mockFetch = vi.fn();
 22: vi.stubGlobal('fetch', mockFetch);
 23: 
 24: // ---------------------------------------------------------------------------
 25: // Helpers
 26: // ---------------------------------------------------------------------------
 27: 
 28: function makeQualityResponse(overrides: Partial<Record<string, unknown>> = {}) {
 29:   return {
 30:     metrics: [
 31:       { name: 'relevance', score: 0.85, evaluatorType: 'seed', timestamp: '2026-01-15T12:00:00.000Z' },
 32:       { name: 'coherence', score: 0.9, evaluatorType: 'seed', timestamp: '2026-01-15T12:00:00.000Z' },
 33:     ],
 34:     sessionCount: 3,
 35:     lastUpdated: '2026-01-15T12:00:00.000Z',
 36:     ...overrides,
 37:   };
 38: }
 39: 
 40: function makeOkResponse(body: unknown): Response {
 41:   return {
 42:     ok: true,
 43:     status: 200,
 44:     json: () => Promise.resolve(body),
 45:   } as Response;
 46: }
 47: 
 48: function makeErrorResponse(status = 500): Response {
 49:   return {
 50:     ok: false,
 51:     status,
 52:     json: () => Promise.resolve({ error: 'Server error' }),
 53:   } as Response;
 54: }
 55: 
 56: /** Flush the initial fetchLive() promise without advancing the polling interval. */
 57: async function flushInitialFetch() {
 58:   await act(async () => {
 59:     await vi.advanceTimersByTimeAsync(0);
 60:   });
 61: }
 62: 
 63: /** Advance by exactly one poll interval (30s) to trigger the setInterval callback. */
 64: async function advanceOnePoll() {
 65:   await act(async () => {
 66:     await vi.advanceTimersByTimeAsync(30_000);
 67:   });
 68: }
 69: 
 70: // ---------------------------------------------------------------------------
 71: // Tests
 72: // ---------------------------------------------------------------------------
 73: 
 74: describe('useQualityLive', () => {
 75:   beforeEach(() => {
 76:     vi.useFakeTimers();
 77:     mockFetch.mockReset();
 78:   });
 79: 
 80:   afterEach(() => {
 81:     vi.useRealTimers();
 82:     vi.restoreAllMocks();
 83:     // Ensure visibilityState is restored even if a test fails mid-mutation
 84:     Object.defineProperty(document, 'visibilityState', { value: 'visible', writable: true, configurable: true });
 85:   });
 86: 
 87:   it('starts with isLoading=true, data=null, error=null', () => {
 88:     mockFetch.mockReturnValue(new Promise(() => {}));
 89:     const { result } = renderHook(() => useQualityLive());
 90:     expect(result.current.isLoading).toBe(true);
 91:     expect(result.current.data).toBeNull();
 92:     expect(result.current.error).toBeNull();
 93:   });
 94: 
 95:   it('sets data and clears isLoading after successful fetch', async () => {
 96:     const payload = makeQualityResponse();
 97:     mockFetch.mockResolvedValue(makeOkResponse(payload));
 98: 
 99:     const { result } = renderHook(() => useQualityLive());
100:     await flushInitialFetch();
101: 
102:     expect(result.current.isLoading).toBe(false);
103:     expect(result.current.data).toEqual(payload);
104:     expect(result.current.error).toBeNull();
105:   });
106: 
107:   it('sets error and clears isLoading on non-ok response', async () => {
108:     mockFetch.mockResolvedValue(makeErrorResponse(500));
109: 
110:     const { result } = renderHook(() => useQualityLive());
111:     await flushInitialFetch();
112: 
113:     expect(result.current.isLoading).toBe(false);
114:     expect(result.current.error).toBeInstanceOf(Error);
115:     expect(result.current.error?.message).toContain('500');
116:     expect(result.current.data).toBeNull();
117:   });
118: 
119:   it('sets error on network failure (fetch throws)', async () => {
120:     mockFetch.mockRejectedValue(new Error('Network error'));
121: 
122:     const { result } = renderHook(() => useQualityLive());
123:     await flushInitialFetch();
124: 
125:     expect(result.current.isLoading).toBe(false);
126:     expect(result.current.error).toBeInstanceOf(Error);
127:     expect(result.current.error?.message).toBe('Network error');
128:   });
129: 
130:   it('calls fetch once on mount with correct URL', async () => {
131:     mockFetch.mockResolvedValue(makeOkResponse(makeQualityResponse()));
132: 
133:     renderHook(() => useQualityLive());
134:     await flushInitialFetch();
135: 
136:     expect(mockFetch).toHaveBeenCalledTimes(1);
137:     expect(mockFetch).toHaveBeenCalledWith(
138:       expect.stringContaining('/api/quality/live')
139:     );
140:   });
141: 
142:   it('polls again after POLL_INTERVAL_MS (30s)', async () => {
143:     mockFetch.mockResolvedValue(makeOkResponse(makeQualityResponse()));
144: 
145:     renderHook(() => useQualityLive());
146:     await flushInitialFetch();
147:     expect(mockFetch).toHaveBeenCalledTimes(1);
148: 
149:     await advanceOnePoll();
150:     expect(mockFetch).toHaveBeenCalledTimes(2);
151:   });
152: 
153:   it('polls a third time after two intervals', async () => {
154:     mockFetch.mockResolvedValue(makeOkResponse(makeQualityResponse()));
155: 
156:     renderHook(() => useQualityLive());
157:     await flushInitialFetch();
158:     expect(mockFetch).toHaveBeenCalledTimes(1);
159: 
160:     await advanceOnePoll();
161:     await advanceOnePoll();
162:     expect(mockFetch).toHaveBeenCalledTimes(3);
163:   });
164: 
165:   it('stops polling after unmount', async () => {
166:     mockFetch.mockResolvedValue(makeOkResponse(makeQualityResponse()));
167: 
168:     const { unmount } = renderHook(() => useQualityLive());
169:     await flushInitialFetch();
170:     expect(mockFetch).toHaveBeenCalledTimes(1);
171: 
172:     unmount();
173:     mockFetch.mockClear();
