 38: /**
 39:  * GET /api/sessions/:sessionId
 40:  *
 41:  * Returns structured session data from all available telemetry sources:
 42:  * traces, logs, and evaluations — queried in parallel by sessionId.
 43:  */
 44: sessionRoutes.get('/sessions/:sessionId', async (c) => {
 45:   const sessionId = c.req.param('sessionId');
 46:   if (!sessionId) return c.json({ error: 'sessionId required' }, HttpStatus.BadRequest);
 47:   const startDate = c.req.query('startDate');
 48:   const endDate = c.req.query('endDate');
 49: 
 50:   try {
 51:     // Query all 3 data sources in parallel
 52:     const [spans, logs, evaluations] = await Promise.all([
 53:       loadSessionSpans(sessionId, startDate, endDate),
 54:       loadLogsBySessionId(sessionId, startDate, endDate),
 55:       loadEvaluationsBySessionId(sessionId, startDate, endDate),
 56:     ]);
 57: 
 58:     // ---- Data Sources Inventory ----
 59:     const traceIds = new Set<string>();
 60:     for (const s of spans) {
 61:       if (s.traceId) traceIds.add(s.traceId);
 62:     }
 63:     const dataSources = {
 64:       traces: { count: spans.length, traceIds: traceIds.size },
 65:       logs: { count: logs.length },
 66:       evaluations: { count: evaluations.length },
 67:       total: spans.length + logs.length + evaluations.length,
 68:     };
 69: 
 70:     // ---- Session Timespan (from evaluation timestamps — trace query strips time fields) ----
 71:     let tsMin = Infinity;
 72:     let tsMax = -Infinity;
 73:     for (const ev of evaluations) {
 74:       const t = new Date(ev.timestamp).getTime();
 75:       if (t < tsMin) tsMin = t;
 76:       if (t > tsMax) tsMax = t;
 77:     }
 78:     for (const l of logs) {
 79:       const t = new Date((l as { timestamp?: string }).timestamp ?? '').getTime();
 80:       if (!isNaN(t)) {
 81:         if (t < tsMin) tsMin = t;
 82:         if (t > tsMax) tsMax = t;
 83:       }
 84:     }
 85:     const timespan = tsMin < Infinity ? {
 86:       start: new Date(tsMin).toISOString(),
 87:       end: new Date(tsMax).toISOString(),
 88:       durationHours: +((tsMax - tsMin) / 3_600_000).toFixed(1),
 89:     } : null;
 90: 
 91:     // ---- Session Info from session-start spans ----
 92:     const sessionStarts = spans.filter(s => attr<string>(s, 'hook.name') === 'session-start');
 93:     const first = sessionStarts[0];
 94:     const last = sessionStarts[sessionStarts.length - 1] ?? first;
 95:     const sessionInfo = first ? {
 96:       projectName: attr<string>(first, 'project.name') ?? 'unknown',
 97:       workingDirectory: attr<string>(first, 'working.directory') ?? '',
 98:       gitRepository: attr<string>(first, 'git.repository') ?? '',
 99:       gitBranch: attr<string>(first, 'git.branch') ?? '',
100:       nodeVersion: attr<string>(first, 'node.version') ?? '',
101:       resumeCount: sessionStarts.length,
102:       initialMessageCount: attr<number>(first, 'context.message_count') ?? 0,
103:       initialContextTokens: attr<number>(first, 'context.estimated_tokens') ?? 0,
104:       finalMessageCount: attr<number>(last, 'context.message_count') ?? 0,
105:       taskCount: attr<number>(first, 'tasks.active') ?? 0,
106:       uncommittedAtStart: attr<number>(first, 'git.uncommitted') ?? 0,
107:     } : null;
108: 
109:     // ---- Token Progression ----
110:     const tokenProgression = spans
111:       .filter(s => attr<string>(s, 'hook.name') === 'token-metrics-extraction')
112:       .map(s => ({
113:         messages: attr<number>(s, 'tokens.messages') ?? 0,
114:         inputTokens: attr<number>(s, 'tokens.input') ?? 0,
115:         outputTokens: attr<number>(s, 'tokens.output') ?? 0,
116:         cacheRead: attr<number>(s, 'tokens.cache_read') ?? 0,
117:         cacheCreation: attr<number>(s, 'tokens.cache_creation') ?? 0,
118:         model: attr<string>(s, 'tokens.model') ?? '',
119:       }))
120:       .sort((a, b) => a.messages - b.messages);
121: 
122:     // ---- Token Totals ----
123:     const tokenTotals = {
124:       input: 0, output: 0, cacheRead: 0, cacheCreation: 0, messages: 0,
125:       models: {} as Record<string, number>,
126:     };
127:     for (const t of tokenProgression) {
128:       tokenTotals.input += t.inputTokens;
129:       tokenTotals.output += t.outputTokens;
130:       tokenTotals.cacheRead += t.cacheRead;
131:       tokenTotals.cacheCreation += t.cacheCreation;
132:       tokenTotals.messages += t.messages;
133:       if (t.model) tokenTotals.models[t.model] = (tokenTotals.models[t.model] ?? 0) + 1;
134:     }
135: 
136:     // ---- Tool Usage ----
137:     const toolUsage: Record<string, number> = {};
138:     for (const s of spans) {
139:       if (attr<string>(s, 'hook.type') === 'builtin' && attr<string>(s, 'hook.trigger') === 'PostToolUse') {
140:         const tool = attr<string>(s, 'builtin.tool') ?? 'unknown';
141:         toolUsage[tool] = (toolUsage[tool] ?? 0) + 1;
142:       }
143:     }
144: 
145:     // ---- MCP Usage ----
146:     const mcpUsage: Record<string, number> = {};
147:     for (const s of spans) {
148:       if (attr<string>(s, 'hook.type') === 'mcp' && attr<string>(s, 'hook.trigger') === 'PostToolUse') {
149:         const tool = attr<string>(s, 'mcp.tool') ?? 'unknown';
150:         mcpUsage[tool] = (mcpUsage[tool] ?? 0) + 1;
151:       }
152:     }
153: 
154:     // ---- Span Breakdown + Hook Latency ----
155:     const spanBreakdown: Record<string, number> = {};
156:     const hookDurations: Record<string, number[]> = {};
157:     for (const s of spans) {
158:       spanBreakdown[s.name] = (spanBreakdown[s.name] ?? 0) + 1;
159:       const ms = s.durationMs ?? 0;
160:       if (ms > 0) {
161:         if (!hookDurations[s.name]) hookDurations[s.name] = [];
162:         hookDurations[s.name].push(ms);
163:       }
164:     }
165:     const hookLatency: Record<string, { count: number; avg: number; p50: number; p95: number; max: number }> = {};
166:     for (const [name, durations] of Object.entries(hookDurations)) {
167:       const sorted = durations.sort((a, b) => a - b);
168:       hookLatency[name] = {
169:         count: sorted.length,
170:         avg: +(sorted.reduce((a, b) => a + b, 0) / sorted.length).toFixed(1),
171:         p50: +percentile(sorted, 50).toFixed(1),
172:         p95: +percentile(sorted, 95).toFixed(1),
173:         max: +sorted[sorted.length - 1].toFixed(1),
174:       };
175:     }
176: 
177:     // ---- Error Categorization ----
178:     const errorsByCategory: Record<string, number> = {};
179:     const errorDetails: Array<{
180:       spanName: string;
181:       tool?: string;
182:       errorType?: string;
183:       filePath?: string;
184:     }> = [];
185:     for (const s of spans) {
186:       const hasError = attr<boolean>(s, 'builtin.has_error') === true
187:         || attr<boolean>(s, 'agent.has_error') === true
188:         || s.status?.code === 2;
189:       if (!hasError) continue;
190:       const tool = attr<string>(s, 'builtin.tool') ?? attr<string>(s, 'agent.type') ?? 'unknown';
191:       const errType = attr<string>(s, 'builtin.error_type') ?? 'unknown';
192:       const key = `${tool} -> ${errType}`;
193:       errorsByCategory[key] = (errorsByCategory[key] ?? 0) + 1;
194:       errorDetails.push({
195:         spanName: s.name,
196:         tool,
197:         errorType: errType,
198:         filePath: attr<string>(s, 'builtin.file_path'),
199:       });
