 9: /**
10:  * GET /api/quality/live
11:  * Returns latest quality evaluation results from today's evaluations.
12:  * Response: { metrics, sessionCount, lastUpdated }
13:  */
14: qualityRoutes.get('/quality/live', async (c) => {
15:   try {
16:     const now = new Date();
17:     const start = new Date(now.getTime() - LIVE_WINDOW_MS);
18: 
19:     const evaluationsByMetric = await loadEvaluationsByMetric(
20:       start.toISOString(),
21:       now.toISOString(),
22:     );
23: 
24:     const metrics: LiveMetric[] = [];
25:     const sessionIds = new Set<string>();
26:     let latestTimestamp = '';
27: 
28:     for (const [name, evals] of evaluationsByMetric) {
29:       // Take last EVAL_LIMIT records, sorted by timestamp desc
30:       const sorted = evals
31:         .slice()
32:         .sort((a, b) => b.timestamp.localeCompare(a.timestamp))
33:         .slice(0, EVAL_LIMIT);
34: 
35:       // Track sessions
36:       for (const ev of sorted) {
37:         if (ev.traceId) sessionIds.add(ev.traceId);
38:       }
39: 
40:       // Latest eval for this metric
41:       const latest = sorted[0];
42:       if (latest && latest.scoreValue != null) {
43:         metrics.push({
44:           name,
45:           score: latest.scoreValue,
46:           evaluatorType: latest.evaluatorType ?? 'unknown',
47:           timestamp: latest.timestamp,
48:         });
49:         if (latest.timestamp > latestTimestamp) {
50:           latestTimestamp = latest.timestamp;
51:         }
52:       }
53:     }
54: 
55:     // Sort by metric name for stable ordering
56:     metrics.sort((a, b) => a.name.localeCompare(b.name));
57: 
58:     const response: QualityLiveData = {
59:       metrics,
60:       sessionCount: sessionIds.size,
61:       lastUpdated: latestTimestamp || now.toISOString(),
62:     };
63: 
64:     return c.json(response);
65:   } catch (err) {
66:     return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
67:   }
