172: trendRoutes.get('/trends', async (c) => {
173:   const periodResult = PeriodSchema.safeParse(c.req.query('period'));
174:   if (!periodResult.success) {
175:     return c.json({ error: ErrorMessage.InvalidPeriod }, HttpStatus.BadRequest);
