22:       </div>
23: 
24:       <div className="flex-col gap-1">
25:         {stages.map((stage, idx) => {
26:           const widthPct = Math.max(2, (stage.entryCount / maxCount) * 100);
27:           const dropoff = dropoffs[idx];
28:           const showDropoff = dropoff && dropoff.dropped > 0;
29: 
30:           return (
31:             <div key={stage.name}>
32:               {/* Stage bar */}
33:               <div className="flex-center gap-3">
34:                 <div
35:                   className="d-flex"
36:                   style={{
37:                     width: `${widthPct}%`,
38:                     minWidth: 40,
39:                     height: 32,
40:                     background: `var(--stage-${stage.name}, var(--accent))`,
41:                     borderRadius: 4,
42:                     alignItems: 'center',
43:                     justifyContent: 'space-between',
44:                     padding: '0 10px',
45:                     transition: 'width 0.3s ease',
46:                   }}
47:                   role="meter"
48:                   aria-label={`${stage.displayName}: ${stage.entryCount} evaluations`}
49:                   aria-valuenow={stage.entryCount}
50:                   aria-valuemin={0}
51:                   aria-valuemax={maxCount}
52:                 >
53:                   <span className="text-xs font-semibold" style={{ color: '#fff', whiteSpace: 'nowrap' }}>
54:                     {stage.displayName}
55:                   </span>
56:                   <span className="mono-xs" style={{ color: '#fff', whiteSpace: 'nowrap' }}>
57:                     {stage.entryCount.toLocaleString()}
58:                   </span>
59:                 </div>
60:               </div>
61: 
62:               {/* Drop-off indicator */}
63:               {showDropoff && (
64:                 <div className="text-xs" style={{
65:                   color: dropoff.dropoffPercent > 20 ? 'var(--status-warning)' : 'var(--text-secondary)',
66:                   paddingLeft: 10,
67:                   margin: '2px 0',
68:                 }}>
69:                   {'\u2193'} -{dropoff.dropped.toLocaleString()} ({dropoff.dropoffPercent.toFixed(1)}% drop)
70:                 </div>
71:               )}
72:             </div>
73:           );
74:         })}
75:       </div>
76: 
77:       {/* Screen reader summary table */}
78:       <table className="sr-only" aria-label="Pipeline stage details">
79:         <thead>
80:           <tr><th>Stage</th><th>Entry</th><th>Exit</th><th>Drop-off</th></tr>
