 13: function computePeriodDates(period: string): { start: string; end: string } {
 14:   const now = new Date();
 15:   const ms: Record<string, number> = {
 16:     '24h': 24 * 60 * 60 * 1000,
 17:     '7d': 7 * 24 * 60 * 60 * 1000,
 18:     '30d': 30 * 24 * 60 * 60 * 1000,
 19:   };
 20:   const start = new Date(now.getTime() - (ms[period] ?? ms['7d']));
 21:   return { start: start.toISOString(), end: now.toISOString() };
 22: }
 23: 
 24: /** Bucket evaluations into N time bins and return avg scores per bucket */
 25: function computeSparklineData(
 26:   evaluations: EvaluationResult[],
 27:   startMs: number,
 28:   endMs: number,
 29:   buckets: number,
 30: ): (number | null)[] {
 31:   const range = endMs - startMs;
 32:   if (range <= 0 || evaluations.length === 0) return [];
 33: 
 34:   const bucketWidth = range / buckets;
 35:   const sums = new Array(buckets).fill(0);
 36:   const counts = new Array(buckets).fill(0);
 37: 
 38:   for (const ev of evaluations) {
 39:     if (ev.scoreValue === null || !Number.isFinite(ev.scoreValue)) continue;
 40:     const ts = new Date(ev.timestamp).getTime();
 41:     const idx = Math.min(Math.floor((ts - startMs) / bucketWidth), buckets - 1);
 42:     if (idx >= 0) {
 43:       sums[idx] += ev.scoreValue;
 44:       counts[idx]++;
 45:     }
 46:   }
 47: 
 48:   return sums.map((s, i) => counts[i] > 0 ? s / counts[i] : null);
 49: }
