 8: /** Filter out rule-based per-span evaluations; they have incompatible
 9:  *  traceId granularity that inflates the coverage input universe.
10:  *  Keeps LLM judge evals (evaluatorType 'llm', undefined for seed/canary). */
11: function filterJudgeEvaluations(
12:   byMetric: Map<string, EvaluationResult[]>,
13: ): Map<string, EvaluationResult[]> {
14:   const filtered = new Map<string, EvaluationResult[]>();
15:   for (const [metric, evals] of byMetric) {
16:     const judgeEvals = evals.filter(e => e.evaluatorType !== 'rule');
17:     if (judgeEvals.length > 0) {
18:       filtered.set(metric, judgeEvals);
19:     }
20:   }
21:   return filtered;
22: }
