 11: const SHORT_NAMES: Record<string, string> = {
 12:   faithfulness: 'Faith',
 13:   relevance: 'Relev',
 14:   coherence: 'Coher',
 15:   safety: 'Safety',
 16:   instruction_adherence: 'Instr',
 17:   tool_accuracy: 'Tool',
 18:   latency: 'Latency',
 19: };
