 62:   const cols = n + 1;
 63: 
 64:   return (
 65:     <div
 66:       role="table"
 67:       aria-label="Metric correlation matrix"
 68:       className="gap-half w-full"
 69:       style={{
 70:         display: 'grid',
 71:         gridTemplateColumns: `80px repeat(${n}, 1fr)`,
 72:         gridTemplateRows: `32px repeat(${n}, 1fr)`,
 73:         aspectRatio: `${cols} / ${cols}`,
 74:       }}
 75:     >
 76:       {/* Top-left empty corner */}
 77:       <div role="cell" />
 78: 
 79:       {/* Column headers */}
 80:       {metrics.map((m) => (
 81:         <div
 82:           key={`col-${m}`}
 83:           role="columnheader"
 84:           className="text-secondary text-xs font-semibold truncate flex-center"
 85:           style={{
 86:           }}
 87:         >
 88:           {shortName(m)}
 89:         </div>
 90:       ))}
 91: 
 92:       {/* Rows */}
 93:       {metrics.map((rowMetric, ri) => (
 94:         <div key={`row-${rowMetric}`} role="presentation" className="contents">
 95:           {/* Row header */}
 96:           <div
 97:             role="rowheader"
 98:             className="text-secondary text-xs font-semibold truncate flex-center"
 99:             style={{
100:               justifyContent: 'flex-end',
101:               paddingRight: 8,
102:             }}
103:           >
104:             {shortName(rowMetric)}
105:           </div>
106: 
107:           {/* Data cells */}
108:           {metrics.map((colMetric, ci) => {
