118:                 ? `${corr.metricA} vs ${corr.metricB}\npearsonR: ${corr.pearsonR.toFixed(3)}\nlagHours: ${corr.lagHours}\npValue: ${corr.pValue?.toFixed(4) ?? 'N/A'}\nsignificant: ${corr.significant}`
119:                 : `${rowMetric} vs ${colMetric}: no data`;
120: 
121:             return (
122:               <div
123:                 key={`${ri}-${ci}`}
124:                 role="cell"
125:                 aria-label={`${rowMetric} vs ${colMetric}: ${value.toFixed(2)}`}
