132:                   color: isDiag ? 'var(--text-secondary)' : contrastText(value),
133:                   borderRadius: 2,
134:                   border: isToxic ? '2px solid #f04438' : 'none',
135:                   animation: isToxic ? 'toxicPulse 2s ease-in-out infinite' : undefined,
136:                   minHeight: 36,
137:                 }}
138:               >
139:                 {value.toFixed(2)}
140:               </div>
141:             );
142:           })}
143:         </div>
144:       ))}
145: 
146:     </div>
147:   );
