  5: interface PipelineHealth {
  6:   evalVolume: number;
  7:   lastEvalAge: string | null;
  8:   evalRate: string;
  9: }
 10: 
 11: function computePipelineHealth(dashboard: QualityDashboardSummary): PipelineHealth {
 12:   let totalSamples = 0;
 13:   let latestTs: string | null = null;
 14: 
 15:   for (const m of dashboard.metrics) {
 16:     totalSamples += m.sampleCount;
 17:   }
 18: 
 19:   // Find most recent evaluation timestamp from worst explanations
 20:   for (const m of dashboard.metrics) {
 21:     const worst = (m as QualityDashboardSummary['metrics'][number] & { worstExplanation?: { timestamp?: string } }).worstExplanation;
 22:     if (worst?.timestamp) {
 23:       if (!latestTs || worst.timestamp > latestTs) latestTs = worst.timestamp;
 24:     }
 25:   }
 26: 
 27:   const lastEvalAge = latestTs ? formatTimestamp(latestTs) : null;
 28: 
 29:   // Compute rate based on period
 30:   const period = dashboard.metrics[0]?.period;
 31:   let periodHours = 168; // default 7d
 32:   if (period) {
 33:     const diffMs = new Date(period.end).getTime() - new Date(period.start).getTime();
 34:     periodHours = Math.max(1, diffMs / (60 * 60 * 1000));
 35:   }
 36:   const perHour = totalSamples / periodHours;
 37:   const evalRate = perHour >= 100 ? `${(perHour / 1000).toFixed(1)}k/hr`
 38:     : perHour >= 1 ? `${perHour.toFixed(0)}/hr`
 39:     : `${(perHour * 24).toFixed(1)}/day`;
 40: 
 41:   return { evalVolume: totalSamples, lastEvalAge, evalRate };
 42: }
 43: 
 44: function formatVolume(n: number): string {
 45:   if (n >= 10000) return `${(n / 1000).toFixed(1)}k`;
 46:   if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
 47:   return String(n);
 48: }
 49: 
 50: export function HealthOverview({ dashboard }: { dashboard: QualityDashboardSummary }) {
 51:   const { overallStatus, summary } = dashboard;
 52:   const pipeline = computePipelineHealth(dashboard);
 53: 
 54:   return (
 55:     <div className="health-banner flex-center" data-status={overallStatus}>
 56:       <div>
 57:         <div className="flex-center gap-3">
 58:           <StatusBadge status={overallStatus} />
 59:           <span className="text-base">
 60:             {overallStatus === 'healthy' && 'All metrics within thresholds'}
 61:             {overallStatus === 'warning' && 'Some metrics need attention'}
 62:             {overallStatus === 'critical' && 'Critical issues detected'}
 63:             {overallStatus === 'no_data' && 'No evaluation data available'}
 64:           </span>
 65:         </div>
 66:         <div className="pipeline-stats d-flex gap-6">
 67:           <div className="pipeline-stat flex-center">
 68:             Eval Volume: <span className="stat-value">{formatVolume(pipeline.evalVolume)}</span>
 69:           </div>
 70:           <div className="pipeline-stat flex-center">
 71:             Rate: <span className="stat-value">{pipeline.evalRate}</span>
 72:           </div>
 73:           {pipeline.lastEvalAge && (
 74:             <div className="pipeline-stat flex-center">
 75:               Last Eval: <span className="stat-value">{pipeline.lastEvalAge}</span>
 76:             </div>
 77:           )}
 78:         </div>
 79:       </div>
 80:       <div className="d-flex gap-6">
 81:         <div className="summary-count">
 82:           <div className="value">{summary.totalMetrics}</div>
 83:           <div className="label text-secondary text-xs">Total</div>
 84:         </div>
 85:         <div className="summary-count">
 86:           <div className="value text-healthy">{summary.healthyMetrics}</div>
 87:           <div className="label text-secondary text-xs">Healthy</div>
 88:         </div>
