 15: interface SpanTreeProps {
 16:   spans: Array<{
 17:     spanId: string;
 18:     name: string;
 19:     durationMs?: number;
 20:     status?: { code: number; message?: string };
 21:     attributes?: Record<string, unknown>;
 22:     parentSpanId?: string;
 23:   }>;
 24:   evalsBySpan: Map<string, number>;
 25:   maxDuration: number;
 26: }
 27: 
 28: function buildTree(
 29:   spans: SpanTreeProps['spans'],
 30:   evalsBySpan: Map<string, number>,
 31: ): SpanNode[] {
 32:   const nodeMap = new Map<string, SpanNode>();
 33:   const roots: SpanNode[] = [];
 34: 
 35:   for (const s of spans) {
 36:     nodeMap.set(s.spanId, {
 37:       spanId: s.spanId,
 38:       name: s.name,
 39:       durationMs: s.durationMs,
 40:       status: s.status,
 41:       attributes: s.attributes,
 42:       children: [],
 43:       evalCount: evalsBySpan.get(s.spanId) ?? 0,
 44:     });
 45:   }
 46: 
 47:   for (const s of spans) {
 48:     const node = nodeMap.get(s.spanId)!;
 49:     const parentId = (s as { parentSpanId?: string }).parentSpanId;
 50:     if (parentId && nodeMap.has(parentId)) {
 51:       nodeMap.get(parentId)!.children.push(node);
 52:     } else {
 53:       roots.push(node);
 54:     }
 55:   }
 56: 
 57:   return roots;
 58: }
