 66: function SpanRow({ node, depth, maxDuration }: { node: SpanNode; depth: number; maxDuration: number }) {
 67:   const barPct = maxDuration > 0 && node.durationMs ? Math.min((node.durationMs / maxDuration) * 100, 100) : 0;
 68:   const statusCode = node.status?.code ?? 0;
 69:   const isError = statusCode === 2;
