 71:   const barStyle: CSSProperties = {
 72:     height: 4,
 73:     width: `${barPct}%`,
 74:     background: isError ? 'var(--status-critical)' : 'var(--status-healthy)',
 75:     borderRadius: 2,
 76:     marginTop: 4,
 77:     minWidth: barPct > 0 ? 2 : 0,
 78:   };
 79: 
 80:   return (
 81:     <>
 82:       <div
 83:         className="flex-center gap-2 border-b"
 84:         style={{
 85:           paddingLeft: depth * 20 + 8,
 86:           paddingTop: 8,
 87:           paddingBottom: 8,
 88:         }}
 89:       >
 90:         <span className="text-base" style={{ color: isError ? 'var(--status-critical)' : 'var(--text-primary)' }}>
 91:           {STATUS_ICONS[statusCode]}
 92:         </span>
 93:         <div className="flex-1">
 94:           <div className="text-xs font-medium">{node.name}</div>
 95:           <div className="flex-center gap-2">
 96:             <div className="flex-1" style={{ background: 'var(--bg-surface)', borderRadius: 2, height: 4 }}>
 97:               <div style={barStyle} />
 98:             </div>
 99:             {node.durationMs != null && (
100:               <span className="mono-xs text-secondary nowrap">
101:                 {node.durationMs < 1000 ? `${node.durationMs.toFixed(0)}ms` : `${(node.durationMs / 1000).toFixed(2)}s`}
102:               </span>
103:             )}
104:           </div>
105:         </div>
106:         {node.evalCount > 0 && (
107:           <span className="text-2xs chip font-semibold" style={{
108:             background: 'var(--accent-alpha-10)',
109:             color: 'var(--accent)',
110:           }}>
111:             {plural(node.evalCount, 'eval')}
112:           </span>
113:         )}
114:       </div>
115:       {node.children.map(child => (
116:         <SpanRow key={child.spanId} node={child} depth={depth + 1} maxDuration={maxDuration} />
117:       ))}
118:     </>
119:   );
120: }
