142: agentRoutes.get('/agents/:sessionId', async (c) => {
143:   const sessionId = c.req.param('sessionId');
144:   if (!sessionId) {
145:     return c.json({ error: 'sessionId is required' }, HttpStatus.BadRequest);
146:   }
147: 
148:   try {
149:     const spans = await loadTracesBySessionId(sessionId);
150: 
151:     // Build agentMap from span attributes
152:     const agentMap = new Map<number, string>();
153:     const traceIds = new Set<string>();
154:     spans.forEach((span, i) => {
155:       const agent = span.attributes?.['agent.name'] as string | undefined;
156:       if (agent) agentMap.set(i, agent);
157:       if (span.traceId) traceIds.add(span.traceId);
158:     });
159: 
160:     // Build step scores from spans
161:     const stepScores: StepScore[] = spans.map((span, i) => ({
162:       step: i,
163:       score: typeof span.attributes?.['evaluation.score'] === 'number'
164:         ? span.attributes['evaluation.score'] as number
165:         : (span.status?.code === 2 ? 0 : 1),
166:       explanation: span.name,
167:     }));
168: 
169:     // Compute multi-agent evaluation
170:     const evaluation = computeMultiAgentEvaluation(stepScores, agentMap);
171: 
172:     // Bulk-load evaluations for all traces in the session
173:     const evaluations = await loadEvaluationsByTraceIds([...traceIds]);
174: 
175:     return c.json({
176:       sessionId,
177:       spans,
178:       evaluation,
179:       evaluations,
180:       agentMap: Object.fromEntries(agentMap),
181:     });
182:   } catch (err) {
183:     return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
184:   }
