 39: // -- Shared helpers ---------------------------------------------------------
 40: 
 41: export function truncateText(text: string, max: number): string {
 42:   return text.length > max ? text.slice(0, max) + '...' : text;
 43: }
 44: 
 45: export function truncateId(id: string, max = 10): string {
 46:   if (id.length <= max) return id;
 47:   return `${id.slice(0, 4)}\u2026${id.slice(-4)}`;
 48: }
 49: 
 50: export function formatScore(val: number | null | undefined): string {
 51:   if (val === null || val === undefined) return 'N/A';
 52:   return val.toFixed(4);
 53: }
 54: 
 55: export function plural(count: number, singular: string, suffix = 's'): string {
 56:   return `${count} ${singular}${count !== 1 ? suffix : ''}`;
 57: }
 58: 
 59: export const SCORE_COLORS: Record<ScoreColorBand | 'no_data', string> = {
 60:   excellent: '#26d97f',
 61:   good: '#34d399',
 62:   adequate: '#e5a00d',
 63:   poor: '#f97316',
 64:   failing: '#f04438',
 65:   no_data: '#6b7280',
 66: };
 67: 
 68: /** Shorthand: returns the hex color for a given score + direction. */
 69: export function scoreColor(value: number, direction?: ScoreDirection): string {
 70:   return SCORE_COLORS[scoreColorBand(value, direction)];
 71: }
 72: 
 73: // -- scoreColorBand ---------------------------------------------------------
 74: 
 75: export function scoreColorBand(
 76:   value: number,
 77:   direction: ScoreDirection = 'maximize',
 78: ): ScoreColorBand {
 79:   const v = direction === 'minimize' ? 1 - value : value;
 80:   if (v >= 0.9) return 'excellent';
 81:   if (v >= 0.8) return 'good';
 82:   if (v >= 0.6) return 'adequate';
 83:   if (v >= 0.4) return 'poor';
 84:   return 'failing';
 85: }
 86: 
 87: // -- inferScoreDirection ----------------------------------------------------
 88: 
 89: type ThresholdDirection = 'above' | 'below';
 90: 
 91: export function inferScoreDirection(
 92:   alertDirection: ThresholdDirection | undefined,
 93: ): ScoreDirection {
 94:   return alertDirection === 'above' ? 'minimize' : 'maximize';
 95: }
