 97: // -- Label ordinal encoding -------------------------------------------------
 98: 
 99: const LABEL_ORDINAL_MAP: Record<string, { ordinal: number; category: LabelFilterCategory }> = {
100:   excellent: { ordinal: 4, category: 'Pass' },
101:   highly_relevant: { ordinal: 4, category: 'Pass' },
102:   fully_faithful: { ordinal: 4, category: 'Pass' },
103:   perfect: { ordinal: 4, category: 'Pass' },
104:   relevant: { ordinal: 3, category: 'Pass' },
105:   good: { ordinal: 3, category: 'Pass' },
106:   faithful: { ordinal: 3, category: 'Pass' },
107:   pass: { ordinal: 3, category: 'Pass' },
108:   correct: { ordinal: 3, category: 'Pass' },
109:   coherent: { ordinal: 3, category: 'Pass' },
110:   partial: { ordinal: 2, category: 'Review' },
111:   borderline: { ordinal: 2, category: 'Review' },
112:   adequate: { ordinal: 2, category: 'Review' },
113:   mixed: { ordinal: 2, category: 'Review' },
114:   off_topic: { ordinal: 1, category: 'Fail' },
115:   irrelevant: { ordinal: 1, category: 'Fail' },
116:   unfaithful: { ordinal: 1, category: 'Fail' },
117:   fail: { ordinal: 1, category: 'Fail' },
118:   incorrect: { ordinal: 1, category: 'Fail' },
119:   incoherent: { ordinal: 1, category: 'Fail' },
120:   hallucinated: { ordinal: 0, category: 'Fail' },
121:   fabricated: { ordinal: 0, category: 'Fail' },
122:   toxic: { ordinal: 0, category: 'Fail' },
123:   dangerous: { ordinal: 0, category: 'Fail' },
124: };
125: 
126: function normalizeLabel(label: string): string {
127:   return label.toLowerCase().replace(/-/g, '_').trim();
128: }
129: 
130: export function labelToOrdinal(label: string): LabelOrdinal {
131:   const normalized = normalizeLabel(label);
132:   const entry = LABEL_ORDINAL_MAP[normalized];
133:   if (entry) {
134:     return { ordinal: entry.ordinal, category: entry.category, mapped: true };
135:   }
136:   return { ordinal: 2, category: 'Review', mapped: false };
137: }
138: 
139: export function ordinalToCategory(ordinal: number): LabelFilterCategory {
140:   if (ordinal >= 3) return 'Pass';
141:   if (ordinal === 2) return 'Review';
142:   return 'Fail';
143: }
