196: // -- Path/byte formatters ---------------------------------------------------
197: 
198: export function shortPath(fullPath: string): string {
199:   const parts = fullPath.replace(/\\/g, '/').split('/');
200:   return parts.length > 3 ? `\u2026/${parts.slice(-3).join('/')}` : fullPath;
201: }
202: 
203: export function fmtBytes(n: number): string {
204:   if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
205:   if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
206:   return String(n);
207: }
208: 
209: // -- Timestamp formatting ---------------------------------------------------
210: 
211: export function formatTimestamp(ts: string): string {
212:   const d = new Date(ts);
213:   if (isNaN(d.getTime())) return ts || '-';
214:   const now = Date.now();
215:   const diffMs = now - d.getTime();
216:   const diffMin = Math.floor(diffMs / 60_000);
217:   if (diffMin < 1) return 'just now';
218:   if (diffMin < 60) return `${diffMin}m ago`;
219:   const diffHr = Math.floor(diffMin / 60);
220:   if (diffHr < 24) return `${diffHr}h ago`;
221:   const diffDay = Math.floor(diffHr / 24);
222:   if (diffDay < 7) return `${diffDay}d ago`;
223:   return d.toLocaleDateString();
