 51: const labelSortFn: SortingFn<EvalRow> = (rowA, rowB) => {
 52:   const a = labelToOrdinal(rowA.original.label ?? 'unknown').ordinal;
 53:   const b = labelToOrdinal(rowB.original.label ?? 'unknown').ordinal;
 54:   return a - b;
 55: };
 56: 
 57: const categoryFilterFn: FilterFn<EvalRow> = (row, _id, filterValue: LabelFilterCategory[]) => {
 58:   if (!filterValue || filterValue.length === 0) return true;
 59:   const category = ordinalToCategory(labelToOrdinal(row.original.label ?? 'unknown').ordinal);
 60:   return filterValue.includes(category);
 61: };
