 92:           evaluatorType={row.evaluatorType}
 93:           explanation={row.explanation}
 94:           traceId={row.traceId}
 95:         />
 96:       );
 97:     },
 98:     sortingFn: 'basic',
 99:   }),
100:   columnHelper.accessor('label', {
101:     header: 'Label',
