181: export function EvaluationTable({ evaluations }: { evaluations: EvalRow[] }) {
182:   const [sorting, setSorting] = useState<SortingState>([]);
183:   const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
184:   const [activeCategories, setActiveCategories] = useState<LabelFilterCategory[]>([]);
185:   const [expanded, setExpanded] = useState<ExpandedState>({});
186: 
187:   const table = useReactTable({
188:     data: evaluations,
189:     columns,
190:     state: { sorting, columnFilters, expanded },
191:     onSortingChange: setSorting,
192:     onColumnFiltersChange: setColumnFilters,
193:     onExpandedChange: setExpanded,
194:     getRowCanExpand: () => true,
195:     getCoreRowModel: getCoreRowModel(),
196:     getSortedRowModel: getSortedRowModel(),
197:     getFilteredRowModel: getFilteredRowModel(),
198:     getExpandedRowModel: getExpandedRowModel(),
199:   });
200: 
201:   const toggleCategory = (cat: LabelFilterCategory) => {
202:     const next = activeCategories.includes(cat)
203:       ? activeCategories.filter((c) => c !== cat)
204:       : [...activeCategories, cat];
205:     setActiveCategories(next);
206:     setColumnFilters(
207:       next.length > 0 ? [{ id: 'label', value: next }] : [],
208:     );
209:   };
210: 
211:   const sortDir = (colId: string): 'ascending' | 'descending' | 'none' => {
212:     const s = sorting.find((entry) => entry.id === colId);
213:     if (!s) return 'none';
214:     return s.desc ? 'descending' : 'ascending';
215:   };
216: 
217:   return (
218:     <div>
219:       <div className="d-flex mb-3 gap-1-5">
220:         {(['Pass', 'Review', 'Fail'] as const).map((cat) => {
221:           const active = activeCategories.includes(cat);
222:           return (
223:             <button
224:               key={cat}
225:               type="button"
226:               onClick={() => toggleCategory(cat)}
227:               className="text-xs font-semibold cursor-pointer"
228:               style={{
229:                 padding: '4px 12px',
230:                 borderRadius: 6,
231:                 border: `1px solid ${CATEGORY_COLORS[cat]}`,
232:                 backgroundColor: active ? `${CATEGORY_COLORS[cat]}30` : 'transparent',
233:                 color: CATEGORY_COLORS[cat],
234:                 opacity: active ? 1 : 0.6,
235:                 transition: 'opacity 0.15s, background-color 0.15s',
236:               }}
237:             >
238:               {cat}
239:             </button>
240:           );
241:         })}
242:       </div>
243:       <table className="eval-table">
244:         <thead>
245:           {table.getHeaderGroups().map((hg) => (
246:             <tr key={hg.id}>
247:               {hg.headers.map((header) => {
248:                 const canSort = header.column.getCanSort();
249:                 return (
250:                   <th
251:                     key={header.id}
252:                     onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
253:                     className="select-none"
254:                     style={{ cursor: canSort ? 'pointer' : 'default' }}
255:                     aria-sort={canSort ? sortDir(header.id) : undefined}
256:                   >
257:                     {flexRender(header.column.columnDef.header, header.getContext())}
258:                     {canSort && (
259:                       <span style={{ marginLeft: 4, fontSize: 'var(--font-size-2xs)' }}>
260:                         {{ asc: ' ^', desc: ' v' }[header.column.getIsSorted() as string] ?? ''}
261:                       </span>
262:                     )}
263:                   </th>
264:                 );
265:               })}
266:             </tr>
267:           ))}
