 24: function formatValue(v: number): string {
 25:   return Math.abs(v) < 0.001 ? v.toExponential(2) : v.toFixed(4);
 26: }
 27: 
 28: function formatBreachTime(iso: string): string {
 29:   const hours = (new Date(iso).getTime() - Date.now()) / (1000 * 60 * 60);
 30:   if (hours <= 0) return 'threshold exceeded';
 31:   if (hours < 1) return `${Math.round(hours * 60)}m`;
 32:   if (hours < 48) return `${hours.toFixed(1)}h`;
 33:   return `${(hours / 24).toFixed(1)}d`;
 34: }
 35: 
 36: export function TrendChart({
 37:   trend,
 38:   dynamics,
 39:   warningThreshold,
 40:   criticalThreshold,
 41:   metricName,
 42: }: TrendChartProps) {
 43:   if (!trend) {
 44:     return <EmptyState message="No trend data available" />;
 45:   }
 46: 
 47:   // Build data points: previous and current
 48:   const data: Array<{ label: string; value: number; projected?: number }> = [
 49:     { label: 'Previous', value: trend.previousValue },
 50:     { label: 'Current', value: trend.currentValue },
 51:   ];
 52: 
 53:   // If dynamics has projectedBreachTime or velocity, add projection point
 54:   if (dynamics && dynamics.velocity !== 0) {
 55:     const projectedValue = trend.currentValue + dynamics.velocity;
 56:     data.push({
 57:       label: 'Projected',
 58:       value: trend.currentValue, // actual line ends here
 59:       projected: projectedValue,
 60:     });
 61:     // Set current point's projected value to bridge the dashed line
 62:     data[1].projected = trend.currentValue;
 63:   }
 64: 
 65:   // Compute Y domain with some padding
 66:   const allValues = data.flatMap((d) => [d.value, d.projected].filter((v): v is number => v != null));
 67:   if (warningThreshold != null) allValues.push(warningThreshold);
 68:   if (criticalThreshold != null) allValues.push(criticalThreshold);
 69:   if (allValues.length === 0) {
 70:     return <EmptyState message="Insufficient data" />;
 71:   }
 72:   const yMin = Math.min(...allValues);
 73:   const yMax = Math.max(...allValues);
 74:   const yPad = (yMax - yMin) * 0.15 || 0.05;
 75: 
 76:   return (
 77:     <div>
 78:       <div role="img" aria-label={`Trend chart for ${metricName}`}>
 79:         <ResponsiveContainer width="100%" height={200}>
 80:           <LineChart data={data} margin={CHART_MARGIN}>
 81:             <CartesianGrid {...CHART_GRID_PROPS} />
 82:             <XAxis
 83:               dataKey="label"
 84:               tick={CHART_AXIS_TICK}
 85:               stroke={CHART_COLORS.grid}
 86:             />
 87:             <YAxis
 88:               domain={[yMin - yPad, yMax + yPad]}
 89:               tick={CHART_AXIS_TICK}
 90:               stroke={CHART_COLORS.grid}
 91:               tickFormatter={CHART_YAXIS_TICK_FORMATTER}
 92:               width={CHART_YAXIS_WIDTH}
 93:             />
 94:             <Tooltip
 95:               contentStyle={CHART_TOOLTIP_CONTENT_STYLE}
 96:               formatter={(v: number | undefined) => [v != null ? formatValue(v) : 'N/A', '']}
 97:               labelStyle={CHART_TOOLTIP_LABEL_STYLE}
 98:             />
 99:             {warningThreshold != null && (
100:               <ReferenceLine
101:                 y={warningThreshold}
102:                 stroke={CHART_COLORS.warning}
103:                 strokeDasharray="6 3"
104:                 label={{ value: 'Warning', fill: CHART_COLORS.warning, fontSize: 12, position: 'right' }}
105:               />
106:             )}
107:             {criticalThreshold != null && (
108:               <ReferenceLine
109:                 y={criticalThreshold}
110:                 stroke={CHART_COLORS.critical}
111:                 strokeDasharray="6 3"
112:                 label={{ value: 'Critical', fill: CHART_COLORS.critical, fontSize: 12, position: 'right' }}
113:               />
114:             )}
115:             <Line
116:               type="monotone"
117:               dataKey="value"
118:               stroke={CHART_COLORS.line}
119:               strokeWidth={2}
120:               dot={{ fill: CHART_COLORS.line, r: 4 }}
121:               activeDot={{ r: 6 }}
122:               connectNulls
123:             />
124:             {dynamics && dynamics.velocity !== 0 && (
125:               <Line
126:                 type="monotone"
127:                 dataKey="projected"
128:                 stroke={CHART_COLORS.line}
129:                 strokeWidth={2}
130:                 strokeDasharray="6 4"
131:                 dot={{ fill: CHART_COLORS.line, r: 3, strokeDasharray: '' }}
132:                 connectNulls
133:               />
134:             )}
135:           </LineChart>
136:         </ResponsiveContainer>
137:       </div>
138:       {dynamics && (
139:         <div className="flex-wrap text-xs gap-6 mt-2" style={{
140:           padding: 'var(--space-2) 0',
141:           color: CHART_COLORS.text,
142:         }}>
143:           <div>
144:             <span className="font-semibold">Velocity:</span>{' '}
145:             <span className="mono">
146:               {dynamics.velocity >= 0 ? '+' : ''}{formatValue(dynamics.velocity)}/hr
147:             </span>
148:           </div>
149:           <div>
150:             <span className="font-semibold">Acceleration:</span>{' '}
151:             <span className="mono">
152:               {dynamics.acceleration >= 0 ? '+' : ''}{formatValue(dynamics.acceleration)}/hr
153:             </span>
154:           </div>
155:           {dynamics.projectedBreachTime && (
156:             <div>
157:               <span className="font-semibold">Breach in:</span>{' '}
158:               <span className="mono" style={{
159:                 color: dynamics.projectedStatus === 'critical' ? CHART_COLORS.critical : CHART_COLORS.warning,
160:               }}>
161:                 {formatBreachTime(dynamics.projectedBreachTime)}
162:               </span>
163:             </div>
164:           )}
165:           <div>
166:             <span className="font-semibold">Confidence:</span>{' '}
167:             <span className="mono">
168:               {(dynamics.confidence * 100).toFixed(0)}%
169:             </span>
170:           </div>
171:         </div>
172:       )}
173:     </div>
174:   );
