 33: export function TrendSeries({ data, metricName }: TrendSeriesProps) {
 34:   if (data.length === 0) {
 35:     return <EmptyState message="No trend data available" />;
 36:   }
 37: 
 38:   const spanMs = new Date(data[data.length - 1].endTime).getTime() - new Date(data[0].startTime).getTime();
 39:   const spanDays = spanMs / (1000 * 60 * 60 * 24);
 40: 
 41:   const chartData = data.map((bucket) => ({
 42:     time: formatTime(bucket.startTime, spanDays),
 43:     avg: bucket.avg,
 44:     p10: bucket.percentiles?.p10 ?? null,
 45:     p50: bucket.percentiles?.p50 ?? null,
 46:     p90: bucket.percentiles?.p90 ?? null,
 47:     count: bucket.count,
 48:   }));
 49: 
 50:   const allVals = chartData.flatMap(d =>
 51:     [d.avg, d.p10, d.p90].filter((v): v is number => v !== null)
 52:   );
 53:   if (allVals.length === 0) {
 54:     return <EmptyState message="No scored evaluations in period" />;
 55:   }
 56: 
 57:   const yMin = Math.min(...allVals);
 58:   const yMax = Math.max(...allVals);
 59:   const yPad = (yMax - yMin) * 0.15 || 0.05;
 60: 
 61:   return (
 62:     <div role="img" aria-label={`Time series trend for ${metricName}`}>
 63:       <ResponsiveContainer width="100%" height={220}>
 64:         <ComposedChart data={chartData} margin={CHART_MARGIN}>
 65:           <CartesianGrid {...CHART_GRID_PROPS} />
 66:           <XAxis
 67:             dataKey="time"
 68:             tick={CHART_AXIS_TICK}
 69:             stroke={CHART_COLORS.grid}
 70:           />
 71:           <YAxis
 72:             domain={[yMin - yPad, yMax + yPad]}
 73:             tick={CHART_AXIS_TICK}
 74:             stroke={CHART_COLORS.grid}
 75:             tickFormatter={CHART_YAXIS_TICK_FORMATTER}
 76:             width={CHART_YAXIS_WIDTH}
 77:           />
 78:           <Tooltip
 79:             contentStyle={CHART_TOOLTIP_CONTENT_STYLE}
 80:             formatter={(v: number | string | undefined, name?: string) => [
 81:               typeof v === 'number' ? v.toFixed(4) : 'N/A',
 82:               name === 'avg' ? 'Average' : (name ?? '').toUpperCase(),
 83:             ]}
 84:             labelStyle={CHART_TOOLTIP_LABEL_STYLE}
 85:           />
 86:           {/* P10-P90 band */}
 87:           <Area
 88:             type="monotone"
 89:             dataKey="p90"
 90:             stroke="none"
 91:             fill={TREND_COLORS.band}
 92:             connectNulls
 93:           />
 94:           <Area
 95:             type="monotone"
 96:             dataKey="p10"
 97:             stroke="none"
 98:             fill={TREND_COLORS.background}
 99:             connectNulls
100:           />
101:           {/* P50 line */}
102:           <Line
103:             type="monotone"
104:             dataKey="p50"
105:             stroke={TREND_COLORS.bandStroke}
106:             strokeWidth={1}
107:             strokeDasharray="4 3"
108:             dot={false}
109:             connectNulls
110:           />
111:           {/* Average line */}
112:           <Line
113:             type="monotone"
114:             dataKey="avg"
115:             stroke={CHART_COLORS.line}
116:             strokeWidth={2}
117:             dot={{ fill: CHART_COLORS.line, r: 3 }}
118:             activeDot={{ r: 5 }}
119:             connectNulls
120:           />
121:         </ComposedChart>
122:       </ResponsiveContainer>
123:       <div className="flex-center justify-center gap-4 mt-1 text-xs" style={{ color: CHART_COLORS.text }}>
124:         <span><span style={{ color: CHART_COLORS.line }}>&#9473;</span> avg</span>
125:         <span><span style={{ opacity: 0.5 }}>- -</span> p50</span>
126:         <span><span style={{ opacity: 0.3 }}>&#9608;</span> p10-p90</span>
127:       </div>
128:     </div>
129:   );
