266:           )}
267:         </Route>
268:         <Route path="/metrics/:metricName">
269:           {(params) => (
270:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
271:               <MetricDetailPage name={params.metricName} period={period} />
272:             </ErrorBoundary>
273:           )}
274:         </Route>
275:         <Route path="/evaluations/trace/:traceId">
276:           {(params) => (
277:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
278:               <EvaluationDetailPage traceId={params.traceId} />
279:             </ErrorBoundary>
280:           )}
281:         </Route>
282:         <Route path="/correlations">
283:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
284:             <CorrelationsPage period={period} />
285:           </ErrorBoundary>
286:         </Route>
287:         <Route path="/coverage">
288:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
289:             <CoveragePage period={period} />
290:           </ErrorBoundary>
291:         </Route>
292:         <Route path="/pipeline">
293:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
294:             <PipelinePage period={period} />
295:           </ErrorBoundary>
296:         </Route>
297:         <Route path="/compliance">
298:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
299:             <CompliancePage period={period} />
300:           </ErrorBoundary>
301:         </Route>
302:         <Route path="/agents">
303:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
304:             <AgentsPage period={period} />
305:           </ErrorBoundary>
306:         </Route>
307:         <Route path="/traces/:traceId">
308:           {(params) => (
309:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
310:               <TraceDetailPage traceId={params.traceId} />
311:             </ErrorBoundary>
312:           )}
313:         </Route>
314:         <Route path="/agents/:sessionId">
315:           {(params) => (
316:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
317:               <AgentSessionPage sessionId={params.sessionId} />
318:             </ErrorBoundary>
319:           )}
320:         </Route>
321:         <Route path="/sessions/:sessionId">
322:           {(params) => (
323:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
324:               <SessionDetailPage sessionId={params.sessionId} />
325:             </ErrorBoundary>
326:           )}
327:         </Route>
328:         <Route>
329:           <div className="empty-state">
330:             <h2>Page Not Found</h2>
331:             <p><Link href="/">Go to dashboard</Link></p>
332:           </div>
333:         </Route>
334:       </Switch>
335:     </Layout>
336:     </RoleProvider>
337:     </KeyboardNavProvider>
338:     </Router>
339:   );
