 11: const COLUMN_COUNT = 7;
 12: const RATE_LIMIT_BADGE_BG = 'var(--bg-status-warning)';
 13: 
 14: type SortKey = 'invocations' | 'errorRate' | 'sessionCount' | 'avgOutputSize';
 15: 
 16: function errorRateColor(rate: number): string {
 17:   if (rate === 0) return 'var(--status-healthy)';
 18:   if (rate < ERROR_RATE_WARNING_THRESHOLD) return 'var(--status-warning)';
 19:   return 'var(--status-critical)';
 20: }
