 22: 
 23: interface AgentActivityPanelProps {
 24:   agents: AgentStat[];
 25: }
 26: 
 27: export function AgentActivityPanel({ agents }: AgentActivityPanelProps) {
 28:   const [sort, setSort] = useState<SortKey>('invocations');
 29:   const [asc, setAsc] = useState(false);
 30:   const [expanded, setExpanded] = useState<string | null>(null);
 31: 
 32:   const colorIndex = useMemo(
 33:     () => new Map(agents.map((a, i) => [a.agentName, AGENT_PALETTE[i % AGENT_PALETTE.length]])),
 34:     [agents],
 35:   );
 36: 
 37:   // React 18+ batches both setState calls in event handlers atomically
 38:   const toggleSort = useCallback((key: SortKey) => {
 39:     if (key === sort) {
 40:       setAsc(v => !v);
 41:     } else {
 42:       setSort(key);
 43:       setAsc(false);
 44:     }
 45:   }, [sort]);
 46: 
 47:   if (agents.length === 0) {
 48:     return <EmptyState message="No agent activity recorded for this period." />;
 49:   }
 50: 
 51:   const maxInvocations = Math.max(...agents.map(a => a.invocations), 1);
 52: 
 53:   const sorted = [...agents].sort((a, b) => {
 54:     const diff = a[sort] < b[sort] ? -1 : a[sort] > b[sort] ? 1 : 0;
 55:     return asc ? diff : -diff;
 56:   });
 57: 
 58:   const sortIndicator = (key: SortKey) =>
 59:     sort === key ? (asc ? ' \u2191' : ' \u2193') : '';
 60: 
 61:   return (
 62:     <div className="overflow-x-auto">
 63:       <table className="sla-table" style={{ minWidth: 640 }}>
 64:         <thead>
 65:           <tr>
 66:             <th style={{ width: '30%' }}>Agent</th>
 67:             <th className="cursor-pointer select-none" onClick={() => toggleSort('invocations')}>
 68:               Invocations{sortIndicator('invocations')}
 69:             </th>
 70:             <th className="cursor-pointer select-none" onClick={() => toggleSort('errorRate')}>
 71:               Error Rate{sortIndicator('errorRate')}
 72:             </th>
 73:             <th className="cursor-pointer select-none" onClick={() => toggleSort('sessionCount')}>
 74:               Sessions{sortIndicator('sessionCount')}
 75:             </th>
 76:             <th className="cursor-pointer select-none" onClick={() => toggleSort('avgOutputSize')}>
 77:               Avg Output{sortIndicator('avgOutputSize')}
 78:             </th>
 79:             <th>Rate Limits</th>
 80:             <th>Source</th>
 81:           </tr>
 82:         </thead>
 83:         <tbody>
 84:           {sorted.map((agent) => {
 85:             const color = colorIndex.get(agent.agentName) ?? AGENT_PALETTE[0];
 86:             const errColor = errorRateColor(agent.errorRate);
 87:             const invPct = (agent.invocations / maxInvocations) * 100;
 88:             const topSource = Object.entries(agent.sourceTypes).sort((a, b) => b[1] - a[1])[0]?.[0];
 89:             const isExpanded = expanded === agent.agentName;
 90:             const hasLinks = agent.sessionIds.length > 0 || agent.traceIds.length > 0;
 91: 
 92:             return (
 93:               <Fragment key={agent.agentName}>
 94:                 <tr
 95:                   className={isExpanded ? 'eval-row-expanded' : ''}
 96:                   style={{ verticalAlign: 'middle', cursor: hasLinks ? 'pointer' : undefined }}
 97:                   onClick={() => hasLinks && setExpanded(isExpanded ? null : agent.agentName)}
 98:                 >
 99:                   {/* Agent name with color accent */}
100:                   <td>
101:                     <div className="flex-center gap-2">
102:                       {hasLinks && (
103:                         <ExpandChevron expanded={isExpanded} className="text-2xs text-muted shrink-0" />
104:                       )}
105:                       <span className="shrink-0 d-inline-block" style={{
106:                         width: 8,
107:                         height: 8,
108:                         borderRadius: '50%',
109:                         background: color,
110:                       }} />
111:                       <span className="mono-xs text-primary break-all">
112:                         {agent.agentName}
113:                       </span>
114:                     </div>
115:                   </td>
116: 
117:                   {/* Invocations with inline bar */}
118:                   <td>
119:                     <div className="flex-center gap-2">
120:                       <span className="mono-xs" style={{ minWidth: 32 }}>
121:                         {agent.invocations}
122:                       </span>
123:                       <BarIndicator value={invPct} color={color} opacity={0.7} className="flex-1" style={{ minWidth: 48 }} />
124:                     </div>
125:                   </td>
126: 
127:                   {/* Error rate */}
128:                   <td>
129:                     <div className="flex-center gap-1-5">
130:                       <span className="mono-xs" style={{
131:                         color: errColor,
132:                       }}>
133:                         {agent.errors > 0 ? `${(agent.errorRate * 100).toFixed(1)}%` : '\u2014'}
134:                       </span>
135:                       {agent.errors > 0 && (
136:                         <span className="text-muted text-xs">
137:                           ({agent.errors})
138:                         </span>
139:                       )}
140:                     </div>
141:                   </td>
142: 
143:                   {/* Session count */}
144:                   <td>
145:                     <span className="mono-xs">
146:                       {agent.sessionCount}
147:                     </span>
148:                   </td>
149: 
150:                   {/* Avg output size */}
151:                   <td>
152:                     <span className="mono-xs text-secondary">
153:                       {fmtBytes(agent.avgOutputSize)}
154:                     </span>
155:                   </td>
156: 
157:                   {/* Rate limits */}
158:                   <td>
159:                     {agent.rateLimitCount > 0 ? (
160:                       <span className="mono-xs" style={{
161:                         color: 'var(--status-warning)',
162:                         background: RATE_LIMIT_BADGE_BG,
163:                         padding: '1px 6px',
164:                         borderRadius: 10,
165:                       }}>
166:                         {agent.rateLimitCount}x
167:                       </span>
168:                     ) : (
169:                       <span className="text-muted text-xs">{'\u2014'}</span>
170:                     )}
171:                   </td>
172: 
173:                   {/* Source type */}
174:                   <td>
175:                     {topSource ? (
176:                       <span className="mono text-muted text-2xs uppercase">
177:                         {topSource}
178:                       </span>
179:                     ) : <span className="text-muted">{'\u2014'}</span>}
180:                   </td>
181:                 </tr>
182: 
183:                 {/* Expanded row: eval summary + sessions + traces */}
184:                 {isExpanded && (
185:                   <tr className="eval-expanded-panel">
186:                     <td colSpan={COLUMN_COUNT} className="border-b" style={{ padding: '0 10px 10px' }}>
187:                       {/* Evaluation summary */}
188:                       <EvalSummaryRow evalSummary={agent.evalSummary} />
189: 
190:                       {/* Daily invocation sparkline */}
191:                       {agent.dailyCounts.length > 1 && agent.dailyCounts.some(v => v > 0) && (
192:                         <div className="border-b-subtle mb-1" style={{
193:                           padding: '10px 0 8px',
194:                         }}>
195:                           <div className="flex-center gap-3">
196:                             <div className="text-xs text-muted uppercase shrink-0">
197:                               Daily Activity
198:                             </div>
199:                             <Sparkline
200:                               data={agent.dailyCounts}
201:                               width={160}
202:                               height={28}
203:                               color={colorIndex.get(agent.agentName) ?? AGENT_PALETTE[0]}
204:                               label={`Daily invocations for ${agent.agentName}`}
205:                             />
206:                             <span className="mono text-muted text-2xs shrink-0">
207:                               peak {Math.max(...agent.dailyCounts)}/day
208:                             </span>
209:                           </div>
210:                         </div>
211:                       )}
212: 
213:                       <div className="gap-4" style={{
214:                         display: 'grid',
215:                         gridTemplateColumns: '1fr 1fr',
216:                         padding: '12px 0 4px',
217:                       }}>
218:                         {/* Sessions column */}
219:                         <div>
220:                           <div className="text-muted mb-1-5 text-xs uppercase">
221:                             Sessions ({agent.sessionCount})
222:                           </div>
223:                           <div className="flex-col gap-1">
224:                             {agent.sessionIds.map(sid => (
225:                               <TruncatedIdLink
226:                                 key={sid}
227:                                 id={sid}
228:                                 href={`/sessions/${sid}`}
229:                                 maxLen={12}
230:                                 onClick={(e) => e.stopPropagation()}
231:                               />
232:                             ))}
233:                             {agent.sessionIds.length === 0 && (
234:                               <span className="text-muted text-xs">none</span>
235:                             )}
236:                             {/* sessionCount === total unique sessions; sessionIds is capped at 50 */}
237:                             {agent.sessionIdsTruncated && (
238:                               <span className="text-muted text-2xs" style={{ fontStyle: 'italic' }}>
239:                                 +{agent.sessionCount - agent.sessionIds.length} more
240:                               </span>
241:                             )}
242:                           </div>
243:                         </div>
244: 
245:                         {/* Traces column */}
246:                         <div>
247:                           <div className="text-muted mb-1-5 text-xs uppercase">
248:                             Traces ({agent.traceIdsTotal ?? agent.traceIds.length})
249:                           </div>
250:                           <div className="flex-col gap-1">
251:                             {agent.traceIds.map(tid => (
252:                               <TruncatedIdLink
253:                                 key={tid}
254:                                 id={tid}
255:                                 href={`/traces/${tid}`}
256:                                 maxLen={12}
257:                                 onClick={(e) => e.stopPropagation()}
258:                               />
259:                             ))}
260:                             {agent.traceIds.length === 0 && (
261:                               <span className="text-muted text-xs">none</span>
262:                             )}
263:                             {agent.traceIdsTruncated && (
264:                               <span className="text-muted text-2xs" style={{ fontStyle: 'italic' }}>
265:                                 +{(agent.traceIdsTotal ?? 0) - agent.traceIds.length} more
266:                               </span>
267:                             )}
268:                           </div>
269:                         </div>
270:                       </div>
271:                     </td>
272:                   </tr>
273:                 )}
274:               </Fragment>
275:             );
276:           })}
277:         </tbody>
278:       </table>
279:     </div>
280:   );
281: }
282: 
283: /** Per-agent evaluation metrics (relevance, coherence, faithfulness, etc.) */
284: function EvalSummaryRow({ evalSummary }: { evalSummary: Record<string, EvalMetricSummary> }) {
285:   const metrics = Object.entries(evalSummary);
286:   if (metrics.length === 0) {
287:     return (
288:       <div className="text-xs text-muted border-b-subtle mb-1" style={{
289:         padding: '10px 0 4px',
290:       }}>
291:         No evaluations linked to this agent.
292:       </div>
293:     );
294:   }
295: 
296:   return (
297:     <div className="border-b-subtle mb-1" style={{
298:       padding: '10px 0 8px',
299:     }}>
300:       <div className="text-muted mb-1-5 text-xs uppercase">
301:         Evaluation Metrics
302:       </div>
303:       <div className="flex-wrap gap-3">
304:         {metrics.map(([name, m]) => {
305:           const barColor = scoreColor(m.avg);
306:           return (
307:             <div key={name} style={{
308:               minWidth: 140,
309:               padding: '8px 10px',
310:               background: 'var(--bg-card)',
311:               border: '1px solid var(--border-subtle)',
312:               borderRadius: 'var(--radius)',
313:             }}>
314:               <div className="text-secondary mb-1 text-xs truncate">
315:                 {name}
316:               </div>
317:               {/* Score bar */}
318:               <div className="flex-center mb-1 gap-2">
319:                 <BarIndicator value={Math.min(m.avg * 100, 100)} color={barColor} className="flex-1" />
320:                 <span className="mono-xs font-semibold text-right" style={{
321:                   color: barColor,
322:                   minWidth: 38,
323:                 }}>
324:                   {m.avg.toFixed(2)}
325:                 </span>
326:               </div>
327:               {/* Min/max range + count */}
328:               <div className="mono text-muted flex-wrap justify-between text-2xs">
329:                 <span>{m.min.toFixed(2)}\u2013{m.max.toFixed(2)}</span>
330:                 <span>n={m.count}</span>
331:               </div>
332:             </div>
333:           );
334:         })}
335:       </div>
336:     </div>
337:   );
338: }
339: 
340: /** Summary bar above the table -- totals at a glance */
341: export function AgentActivitySummary({ agents }: AgentActivityPanelProps) {
342:   const totalInvocations = agents.reduce((s, a) => s + a.invocations, 0);
343:   const totalErrors = agents.reduce((s, a) => s + a.errors, 0);
344:   const totalRateLimits = agents.reduce((s, a) => s + a.rateLimitCount, 0);
345:   const overallErrorRate = totalInvocations > 0 ? (totalErrors / totalInvocations) * 100 : 0;
346: 
347:   return (
348:     <div className="d-flex flex-wrap gap-8 surface-elevated" style={{
349:       padding: 'var(--space-4) var(--space-5)',
350:       marginBottom: 'var(--space-5)',
351:     }}>
352:       {[
353:         { label: 'Agents', value: agents.length },
354:         { label: 'Invocations', value: totalInvocations.toLocaleString() },
355:         {
356:           label: 'Error Rate',
357:           value: totalInvocations > 0 ? `${overallErrorRate.toFixed(1)}%` : '\u2014',
358:           color: overallErrorRate === 0
359:             ? 'var(--status-healthy)'
360:             : overallErrorRate < ERROR_RATE_WARNING_THRESHOLD * 100
361:               ? 'var(--status-warning)'
362:               : 'var(--status-critical)',
363:         },
364:         {
365:           label: 'Rate Limits',
366:           value: totalRateLimits > 0 ? totalRateLimits : '\u2014',
367:           color: totalRateLimits > 0 ? 'var(--status-warning)' : undefined,
368:         },
369:       ].map(({ label, value, color }) => (
370:         <div key={label} className="summary-count">
371:           <div className="value" style={color ? { color } : undefined}>{value}</div>
372:           <div className="label text-secondary text-xs">{label}</div>
373:         </div>
374:       ))}
375:     </div>
376:   );
