417:   color: var(--text-secondary);
418:   cursor: pointer;
419: }
420: 
421: /* Tabs / Role selector */
422: .tab-nav {
423:   display: flex;
424:   gap: var(--space-1);
425:   margin-bottom: var(--space-6);
426:   border-bottom: 1px solid var(--border);
427:   padding-bottom: 0;
428: }
429: .tab-btn {
430:   padding: var(--space-2) var(--space-4);
431:   font-size: var(--font-size-base);
432:   border-bottom: 2px solid transparent;
433:   margin-bottom: -1px;
434:   transition: color var(--transition-fast), border-color var(--transition-fast);
435: }
436: .tab-btn:hover {
437:   color: var(--text-primary);
438: }
439: .tab-btn[aria-selected="true"] {
440:   color: var(--text-primary);
441:   border-bottom-color: var(--accent);
442: }
443: 
444: /* Period selector */
445: .period-selector {
446:   display: inline-flex;
447:   gap: var(--space-1);
448:   background: var(--bg-elevated);
449:   border-radius: var(--radius);
450:   padding: var(--space-px);
451: }
452: .period-btn {
453:   padding: var(--space-1) var(--space-3);
454:   border-radius: var(--radius);
455:   font-size: var(--font-size-xs);
456:   font-family: var(--font-body);
457: }
458: .period-btn.active {
459:   background: var(--bg-card);
460:   color: var(--text-primary);
461: }
462: 
463: /* Header */
464: .header {
465:   justify-content: space-between;
466:   margin-bottom: var(--space-6);
467: }
468: .header h1 {
469:   font-size: var(--font-size-xl);
470:   font-weight: var(--bold);
471: }
472: 
473: /* Loading skeleton */
474: .skeleton {
475:   background: linear-gradient(90deg, var(--bg-card) 25%, var(--bg-elevated) 50%, var(--bg-card) 75%);
476:   background-size: 200% 100%;
477:   animation: skeleton-pulse 1.5s ease-in-out infinite;
478:   border-radius: var(--radius);
479: }
480: @keyframes skeleton-pulse {
481:   0% { background-position: 200% 0; }
482:   100% { background-position: -200% 0; }
483: }
484: 
485: /* Empty state */
486: .empty-state {
487:   text-align: center;
488:   padding: var(--space-16) var(--space-6);
489:   color: var(--text-secondary);
490: }
491: .empty-state h2 {
492:   color: var(--text-primary);
493:   margin-bottom: var(--space-2);
494: }
495: .empty-state code {
496:   background: var(--bg-elevated);
497:   padding: var(--space-px) var(--space-1-5);
498:   border-radius: var(--radius-sm);
499:   font-family: var(--font-mono);
500:   font-size: var(--font-size-xs);
501: }
502: 
503: /* Back link */
504: .back-link {
505:   font-size: var(--font-size-xs);
506:   gap: var(--space-1);
507:   margin-bottom: var(--space-4);
508: }
509: 
510: /* Error state */
511: .error-state {
512:   background: var(--bg-status-critical);
513:   border: 1px solid var(--border-status-critical);
514:   border-radius: var(--radius);
515:   padding: var(--space-6);
516:   text-align: center;
517: }
518: .error-state h2 {
519:   color: var(--status-critical);
520:   margin-bottom: var(--space-2);
521: }
522: .error-state .error-actions {
523:   display: flex;
524:   gap: var(--space-2);
525:   margin-top: var(--space-3);
526:   justify-content: center;
527: }
528: .error-state .error-actions button,
529: .error-state .error-actions a {
530:   padding: var(--space-1-5) var(--space-4);
531:   cursor: pointer;
532: }
533: 
534: /* Section headings */
535: .section-heading {
536:   font-size: var(--font-size-md);
537:   font-weight: var(--bold);
538:   margin-bottom: var(--space-4);
539:   margin-top: var(--space-8);
540: }
541: 
542: /* Session detail — stat item, stat value, stat label, vitals divider, frequency grid */
543: .stat-item {
544:   flex: 1 1 100px;
545:   min-width: 80px;
546:   text-align: center;
547: }
548: 
549: .stat-value {
550:   font-size: var(--font-size-stat);
551:   line-height: 1.1;
552: }
553: 
554: .stat-label {
555:   font-size: var(--font-size-xs);
556:   font-family: var(--font-mono);
557:   color: var(--text-muted);
558:   letter-spacing: var(--stat-label-letter-spacing);
559:   margin-top: var(--space-px);
560: }
561: 
562: .freq-bar-row {
563:   display: grid;
564:   grid-template-columns: 160px 1fr 36px;
565:   align-items: center;
566:   gap: var(--space-2-5);
567:   margin-bottom: var(--space-1-5);
568: }
569: 
570: .vitals-divider {
571:   width: 1px;
572:   background: var(--border-subtle);
573:   margin: 0 var(--space-2);
574:   align-self: stretch;
575: }
576: 
577: .freq-grid {
578:   display: grid;
579:   grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
580:   gap: 0 var(--space-8);
581: }
582: 
583: /* View sections */
584: .view-section {
585:   margin-bottom: var(--space-8);
586: }
587: 
588: /* Refetch indicator */
589: .refetch-indicator {
590:   position: fixed;
591:   top: var(--space-4);
592:   right: var(--space-4);
593:   padding: var(--space-2) var(--space-4);
594:   border-radius: var(--radius);
595:   font-size: var(--font-size-xs);
596:   color: var(--text-secondary);
597:   z-index: 1000;
598:   animation: fade-in var(--transition-fast);
599: }
600: 
601: @keyframes fade-in {
602:   from { opacity: 0; transform: translateY(-8px); }
603:   to { opacity: 1; transform: translateY(0); }
604: }
605: 
606: @keyframes toxicPulse {
607:   0%, 100% { box-shadow: 0 0 0 0 var(--critical-alpha-40); }
608:   50% { box-shadow: 0 0 6px 2px var(--critical-alpha-60); }
609: }
610: 
611: /* Score badge tooltip */
612: .score-badge-wrapper {
613:   position: relative;
614:   cursor: default;
615: }
616: .score-badge-tooltip {
617:   bottom: calc(100% + var(--space-2));
618:   border-radius: var(--radius);
619:   padding: var(--space-2-5) var(--space-3);
620:   min-width: 200px;
621:   max-width: 300px;
622:   z-index: 20;
623:   white-space: normal;
624:   animation: fade-in var(--transition-fast);
625: }
626: .score-badge-wrapper:hover .score-badge-tooltip,
627: .score-badge-wrapper:focus-within .score-badge-tooltip {
628:   display: block;
629: }
630: .tooltip-row {
631:   display: flex;
632:   justify-content: space-between;
633:   gap: var(--space-3);
634:   padding: var(--space-px) 0;
635:   color: var(--text-primary);
636: }
637: .tooltip-link {
638:   display: block;
639:   margin-top: var(--space-2);
640:   padding-top: var(--space-1-5);
641:   border-top: 1px solid var(--border);
642: }
643: 
644: /* Chain of thought panel */
645: .cot-panel {
646:   margin-top: var(--space-1);
647: }
648: .cot-summary {
649:   color: var(--text-secondary);
650:   cursor: pointer;
651:   padding: var(--space-1) 0;
652:   list-style: none;
653: }
654: .cot-summary::-webkit-details-marker {
655:   display: none;
656: }
657: .cot-summary::before {
658:   content: '\25B6';
659:   display: inline-block;
660:   margin-right: var(--space-1-5);
661:   font-size: var(--font-size-2xs);
662:   transition: transform var(--transition-fast);
663: }
664: details[open] > .cot-summary::before {
665:   transform: rotate(90deg);
666: }
667: .cot-content {
668:   font-size: var(--font-size-xs);
669:   color: var(--text-primary);
670:   line-height: 1.6;
671:   padding: var(--space-2) 0 var(--space-1);
672: }
673: 
674: /* Evaluation detail page */
675: .eval-detail-header {
676:   margin-bottom: var(--space-6);
677: }
678: .eval-detail-meta {
679:   gap: var(--space-4);
680:   margin-top: var(--space-2);
681: }
682: .eval-detail-card {
683:   margin-bottom: var(--space-4);
684: }
685: 
686: .eval-summary-card.card:hover {
687:   border-color: var(--accent);
688: }
689: 
690: /* Compound alert card */
691: .alert-compound {
692:   border-left-width: var(--space-1);
693:   background: var(--bg-elevated);
694: }
695: .alert-related {
696:   flex-wrap: wrap;
697:   gap: var(--space-2);
698:   margin-top: var(--space-2);
699: }
700: .alert-metric-link {
701:   font-family: var(--font-mono);
702:   padding: var(--space-px) var(--space-2);
703:   border-radius: var(--radius-pill);
704:   background: var(--accent-alpha-10);
705: }
706: .alert-metric-link:hover {
707:   background: var(--accent-alpha-20);
708: }
709: .remediation-list {
710:   margin-top: var(--space-2);
711:   padding-left: var(--space-5);
712:   color: var(--accent);
713: }
714: .remediation-list li {
715:   margin-bottom: var(--space-1);
716: }
717: .threshold-bar {
718:   position: relative;
719:   height: var(--space-1-5);
720:   background: var(--bg-card);
721:   border-radius: var(--radius-bar);
722:   margin-top: var(--space-2);
723:   overflow: visible;
724: }
725: /* Shared animated bar fill */
726: .threshold-bar-fill,
727: .variance-bar-fill {
728:   height: 100%;
729:   transition: var(--transition-bar);
730: }
731: .threshold-bar-fill { border-radius: var(--radius-bar); }
732: .variance-bar-fill  { border-radius: var(--radius-xs); }
733: .threshold-bar-marker {
734:   position: absolute;
735:   top: -3px;
736:   width: 2px;
737:   height: 12px;
738:   background: var(--text-primary);
739:   border-radius: calc(var(--radius-xs) / 2);
740:   transform: translateX(-1px);
741: }
742: 
743: /* Pipeline health stats in HealthOverview */
744: .pipeline-stat {
745:   gap: var(--space-1);
746: }
747: .pipeline-stat .stat-value {
748:   font-family: var(--font-mono);
749:   color: var(--text-primary);
750:   font-weight: var(--light-bold);
751: }
752: 
753: /* Worst explanation preview on MetricCard */
754: .metric-worst {
755:   font-size: var(--font-size-xs);
756:   color: var(--text-muted);
757:   margin-top: var(--space-2);
758:   line-height: 1.4;
759: }
760: .metric-worst .worst-score {
761:   color: var(--score-failing);
762:   font-family: var(--font-mono);
763:   font-weight: var(--light-bold);
764: }
765: 
766: /* Provenance panel */
767: .provenance-grid,
768: .agreement-grid {
769:   display: grid;
770:   gap: var(--space-1) var(--space-4);
771:   font-family: var(--font-mono);
772:   font-size: var(--font-size-xs);
773: }
774: .provenance-grid { grid-template-columns: auto 1fr; }
775: .provenance-grid .prov-label {
776:   color: var(--text-secondary);
777:   font-family: var(--font-body);
778:   white-space: nowrap;
779: }
780: .provenance-grid .prov-value {
781:   color: var(--text-primary);
782:   word-break: break-all;
783: }
784: .provenance-actions {
785:   display: flex;
786:   gap: var(--space-2);
787:   margin-top: var(--space-3);
788: }
789: .provenance-actions button {
790:   background: var(--bg-surface);
791:   border: 1px solid var(--border);
792:   color: var(--accent);
793:   padding: var(--space-1) var(--space-3);
794:   border-radius: var(--radius-sm);
795:   cursor: pointer;
796:   font-family: var(--font-body);
797: }
798: .provenance-actions button:hover {
799:   background: var(--bg-hover);
800:   border-color: var(--border-accent);
801: }
802: 
803: /* Confidence panel */
804: .confidence-header {
805:   gap: var(--space-2);
806:   margin-bottom: var(--space-3);
807: }
808: .confidence-method {
809:   font-family: var(--font-mono);
810:   font-size: var(--font-size-xs);
811:   color: var(--text-muted);
812: }
813: .agreement-grid { grid-template-columns: 1fr auto auto; }
814: .agreement-grid .ag-header {
815:   color: var(--text-muted);
816:   font-size: var(--font-size-xs);
817:   font-family: var(--font-body);
818:   padding-bottom: var(--space-1);
819:   border-bottom: 1px solid var(--border-subtle);
820: }
821: .agreement-summary .summary-value {
822:   font-family: var(--font-mono);
823:   color: var(--text-primary);
824: }
825: .variance-bar {
826:   gap: var(--space-2);
827: }
828: .variance-bar-track {
829:   flex: 1;
830:   height: var(--space-1);
831:   background: var(--bg-surface);
832:   border-radius: var(--radius-xs);
833:   overflow: hidden;
834: }
835: 
836: /* Mini progress bar — track + fill */
837: .mini-bar {
838:   height: var(--bar-h, 4px);
839:   background: var(--bg-surface);
840:   border-radius: var(--radius-xs);
841:   overflow: hidden;
842: }
843: .mini-bar-fill {
844:   height: 100%;
845:   border-radius: var(--radius-xs);
846:   transition: var(--transition-bar);
847: }
848: 
849: /* Empty card state — card with muted placeholder text */
850: .card--empty {
851:   padding: var(--space-4);
852:   color: var(--text-muted);
853: }
854: 
855: /* Monospace utilities */
856: .mono      { font-family: var(--font-mono); }
857: .mono-2xs  { font-family: var(--font-mono); font-size: var(--font-size-2xs); }
858: .mono-xs   { font-family: var(--font-mono); font-size: var(--font-size-xs); }
859: .mono-base { font-family: var(--font-mono); font-size: var(--font-size-base); }
860: .mono-md   { font-family: var(--font-mono); font-size: var(--font-size-md); }
861: .mono-lg   { font-family: var(--font-mono); font-size: var(--font-size-lg); }
862: .mono-xl   { font-family: var(--font-mono); font-size: var(--font-size-xl); }
863: .mono-2xl  { font-family: var(--font-mono); font-size: var(--font-size-2xl); }
864: 
865: /* Font size */
866: .text-2xs  { font-size: var(--font-size-2xs); }
867: .text-xs   { font-size: var(--font-size-xs); }
868: .text-base { font-size: var(--font-size-base); }
869: .text-md   { font-size: var(--font-size-md); }
870: .text-lg   { font-size: var(--font-size-lg); }
871: .text-xl   { font-size: var(--font-size-xl); }
872: .text-2xl  { font-size: var(--font-size-2xl); }
873: 
874: /* Text color utilities */
875: .text-secondary { color: var(--text-secondary); }
876: .text-muted     { color: var(--text-muted); }
877: 
878: /* Flex layout */
879: .d-flex         { display: flex; }
880: .d-inline-block { display: inline-block; }
881: .flex-center { display: flex; align-items: center; }
882: 
883: /* Text transform */
884: .uppercase { text-transform: uppercase; letter-spacing: var(--label-letter-spacing); }
885: .font-semibold { font-weight: var(--bold); }
886: 
887: /* Chip / pill */
888: .chip { padding: var(--space-px) var(--space-1-5); border-radius: var(--radius-pill); }
889: 
890: /* Gap */
891: .gap-half { gap: var(--space-px); }   /*  1px */
892: .gap-1    { gap: var(--space-1); }      /*  4px */
893: .gap-1-5  { gap: var(--space-1-5); }    /*  6px */
894: .gap-2    { gap: var(--space-2); }      /*  8px */
895: .gap-2-5  { gap: var(--space-2-5); }    /* 10px */
896: .gap-3    { gap: var(--space-3); }      /* 12px */
897: .gap-4    { gap: var(--space-4); }      /* 16px */
898: .gap-5    { gap: var(--space-5); }      /* 20px */
899: .gap-6    { gap: var(--space-6); }      /* 24px */
900: .gap-8    { gap: var(--space-8); }      /* 32px */
901: .gap-16   { gap: var(--space-16); }     /* 64px */
902: 
903: /* Width */
904: .w-full { width: 100%; }
905: 
906: /* Margin */
907: .m-0    { margin: 0; }
908: 
909: /* Margin-bottom */
910: .mb-0   { margin-bottom: 0; }
911: .mb-1   { margin-bottom: var(--space-1); }
912: .mb-1-5 { margin-bottom: var(--space-1-5); }
913: .mb-2   { margin-bottom: var(--space-2); }     /*  8px */
914: .mb-3   { margin-bottom: var(--space-3); }
915: .mb-4   { margin-bottom: var(--space-4); }     /* 16px */
916: 
917: /* Margin-top */
918: .mt-1   { margin-top: var(--space-1); }     /*  4px */
919: .mt-2   { margin-top: var(--space-2); }     /*  8px */
920: .mt-3   { margin-top: var(--space-3); }     /* 12px */
921: .mt-4   { margin-top: var(--space-4); }     /* 16px */
922: 
923: /* Padding */
924: .p-4    { padding: var(--space-4); }        /* 16px */
925: .p-6    { padding: var(--space-6); }        /* 24px */
926: 
927: /* Text align */
928: .text-center { text-align: center; }
929: .text-right  { text-align: right; }
930: .text-left   { text-align: left; }
931: 
932: /* Flex */
933: .flex-wrap          { display: flex; flex-wrap: wrap; }
934: .flex-col           { display: flex; flex-direction: column; }
935: .inline-flex-center { display: inline-flex; align-items: center; }
936: .shrink-0           { flex-shrink: 0; }
937: .flex-1             { flex: 1; }
938: .justify-between    { justify-content: space-between; }
939: .justify-center     { justify-content: center; }
940: 
941: /* Display */
942: .contents { display: contents; }
943: 
944: /* Typography */
945: .font-medium { font-weight: var(--light-bold); }
946: .font-bold   { font-weight: 700; }
947: .nowrap      { white-space: nowrap; }
948: .truncate  { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
949: .break-all { word-break: break-all; }
950: .leading-relaxed { line-height: 1.6; }
951: 
952: /* Button reset */
953: .btn-reset { background: none; border: none; padding: 0; }
954: 
955: /* Expand chevron */
956: .expand-chevron {
957:   display: inline-block;
958:   transition: transform var(--transition-fast);
959:   line-height: 1;
960: }
961: 
962: /* Status colors */
963: .text-healthy  { color: var(--status-healthy); }
964: .text-warning  { color: var(--status-warning); }
965: .text-critical { color: var(--status-critical); }
966: .text-primary  { color: var(--text-primary); }
967: 
968: /* Surface */
969: .surface-elevated { background: var(--bg-elevated); border: 1px solid var(--border); }
970: 
971: /* Link */
972: .link-accent { color: var(--accent); text-decoration: none; }
973: 
974: /* Table cells */
975: .cell-pad      { padding: var(--space-1) var(--space-2-5); }
976: .cell-pad-wide { padding: var(--space-1) var(--space-3); }
977: 
978: /* Border */
979: .border-b        { border-bottom: 1px solid var(--border); }
980: .border-b-subtle { border-bottom: 1px solid var(--border-subtle); }
